var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`......응? 뭐야, 이거?`,JPN:`……うん？　何だ、これ？`,ENG:`Mm? What's all this?`,TWN:`……嗯？這是什麼啊？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`......종신계약? 나랑?`,JPN:`……終身契約を結ぼうって？　俺に言ってんのか？`,ENG:`A lifetime contract? With me?`,TWN:`……終身契約？和我？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`그런 건 우리 대장이랑 할 얘기 아냐?`,JPN:`そんなもん、うちの隊長と話すことじゃねぇのか？`,ENG:`Shouldn't you talk to my cap instead?`,TWN:`這種事情不是應該和我們隊長談嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`음......`,JPN:`うーむ……`,ENG:`Mm...`,TWN:`嗯……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`복잡한 건 잘 모르겠지만, 어쨌든 앞으로도 내 힘이 필요하단 거지?`,JPN:`込み入ったことはわかんねえけど、とにかく、これからも俺の力が必要ってことか？`,ENG:`I don't know what all this is about, but it means you want to keep me, right?`,TWN:`太過複雜的事情我不懂，總之老闆以後也會需要我的力量吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`유미나 그 자식이나 다른 녀석이 아니라, 나 말이야!`,JPN:`あのヤナギ・ミナとか、他の奴じゃなくて、この俺の力が！`,ENG:`Not Mina or the others. You want me!`,TWN:`不是劉米娜那傢伙，也不是其他人，而是需要我！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`뭐야, 그까짓 거라면 얼마든지 도와 줄 수 있지!`,JPN:`まあ、それならお安いご用だぜ。いくらでも力を貸してやるよ！`,ENG:`Sure, I'll let you keep me.`,TWN:`什麼嘛，這點小事不管有多少，我都會幫你的啦！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`YOO_JIN_ALT_SPRING_NULL`,text:{KOREA:`그래서 그 종신계약이라는 건 어떻게 하면 되는데? 얼른 해치워 버리자고!`,JPN:`で、その終身契約とやらはどうやって結ぶんだ？
とっととやっつけようぜ！`,ENG:`So, where do I sign? Let's get this over with!`,TWN:`所以那個叫終身契約的東西怎麼弄？趕快把它解決掉吧！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOO_JIN_ALT_SPRING_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};